/* ===========================================================================
 * Dead CSS selector characterization
 *
 * `src/app.css` ships rule blocks whose selectors are NEVER emitted by app.ts,
 * so they have ZERO observable effect on the rendered UI. They are slated for
 * deletion in a dead-code cleanup. The tests below pin the JS-side invariants
 * that make that deletion provably safe:
 *
 *   - the rendered DOM must never produce an element the removed selectors
 *     could match; and
 *   - any behavior the dead rules *appear* to supply must actually be provided
 *     by an independent mechanism that survives the deletion.
 *
 * Removed selectors under test:
 *   (1) `.breadcrumb .separator`         — breadcrumb separators are class-less
 *       `<span>`s holding the literal "/"; nothing carries `separator`.
 *   (2) `.toolbar label.upload-btn` (+ its `:hover` + the descendant
 *       `input[type=file]` rule) — the upload label uses `btn`, never
 *       `upload-btn`, and the wrapped file input is hidden via the `hidden`
 *       HTML attribute, not via the dead `display:none` descendant rule.
 *
 * (`.folder-row` was formerly in this dead list, but it is now a LIVE class:
 * folder rows and the ".." parent row carry `folder-row` / `parent-row` so the
 * whole row is click-to-browse — see the dedicated suite below.)
 *
 * These assertions pass against the current (pre-cleanup) code AND must keep
 * passing after the dead rules are deleted, because they depend only on the
 * DOM app.ts emits — which the cleanup does not touch. (The environment does
 * not load app.css, so a missing rule cannot change `getComputedStyle` here;
 * these tests instead prove the rule could never have matched anything.)
 *
 * NOTE: these tests pass a `Route` fixture (`browseRoute` / `searchRoute`) as
 * a second argument to `renderBrowse` / `renderSearch`. That argument is a
 * leftover from before the route parameter was removed (see the
 * route-independence suite in `render-orchestration.test.ts`) and is silently
 * ignored at runtime; it is preserved verbatim so the scenario is unchanged.
 * ========================================================================= */
describe('dead CSS selector characterization', () => {
  describe('breadcrumb separators are class-less spans (no `.separator`)', () => {
    /** Leaf <span>s whose visible text is exactly the breadcrumb slash. */
    function slashSeparators(container: Element): HTMLSpanElement[] {
      return Array.from(container.querySelectorAll('span')).filter(
        (s) => (s.textContent ?? '').trim() === '/',
      ) as HTMLSpanElement[];
    }

    it('renders one "/" separator per path segment, each a class-less <span>', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: 'a/b/c', entries: [] }), browseRoute('a/b/c'));

      const separators = slashSeparators(breadcrumb);
      // a/b/c → 3 segments → 3 separators (Home / a / b / c). Verifying the
      // count also pins that the separators are still visibly rendered.
      expect(separators).toHaveLength(3);
      for (const sep of separators) {
        expect(sep.tagName).toBe('SPAN');
        expect(sep.className).toBe('');
        expect(sep.classList.contains('separator')).toBe(false);
      }
      // The dead selector `.breadcrumb .separator` matches nothing.
      expect(document.querySelectorAll('.separator')).toHaveLength(0);
    });

    it('renders no separators for the root path, and still no `.separator` anywhere', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: '', entries: [] }), browseRoute(''));

      expect(slashSeparators(breadcrumb)).toHaveLength(0);
      expect(document.querySelectorAll('.separator')).toHaveLength(0);
    });

    it('search-scope breadcrumbs also use class-less "/" separators', async () => {
      const { breadcrumb } = await setupCleared();
      renderSearch({ query: 'q', path: 'x/y', results: [] }, searchRoute('q', 'x/y'));

      const separators = slashSeparators(breadcrumb);
      expect(separators).toHaveLength(2);
      for (const sep of separators) {
        expect(sep.className).toBe('');
        expect(sep.classList.contains('separator')).toBe(false);
      }
      expect(document.querySelectorAll('.separator')).toHaveLength(0);
    });
  });

  describe('upload control never carries the dead `upload-btn` class', () => {
    it('the upload label uses `btn` (styled by .btn), and no element is `upload-btn`', () => {
      const { uploadLabel } = setup();
      expect(uploadLabel.className).toBe('btn');
      expect(uploadLabel.classList.contains('upload-btn')).toBe(false);
      // The dead selector `.toolbar label.upload-btn` matches nothing.
      expect(document.querySelectorAll('.upload-btn')).toHaveLength(0);
    });

    it('hides the file input via the `visually-hidden` class — NOT the dead `display:none` rule, NOT the `hidden` attribute', () => {
      const { uploadInput, uploadLabel } = setup();
      // The input is visually hidden via the `visually-hidden` sr-only class
      // (a clip-to-1x1 pattern that keeps it focusable for keyboard users —
      // see upload-a11y.test.ts), NOT via the `hidden` HTML attribute (UA
      // `display:none` would eject it from the tab order). Because the hiding
      // is done by the input's own class, deleting the dead descendant rule
      // `.toolbar label.upload-btn input[type=file] { display: none; }` cannot
      // un-hide it.
      expect(uploadInput.hidden).toBe(false);
      expect(uploadInput.hasAttribute('hidden')).toBe(false);
      expect(uploadInput.className).toContain('visually-hidden');
      // The dead descendant selector `.toolbar label.upload-btn input[type=file]`
      // still cannot match this input: its label ancestor is `btn`, never
      // `upload-btn`, so the selector never applied regardless of the input's
      // own class. Deleting that dead rule cannot un-hide it.
      expect(uploadLabel.classList.contains('upload-btn')).toBe(false);
    });
  });
});

/* ===========================================================================
 * Click-to-browse rows — whole-row navigation
 *
 * Folder rows and the ".." parent row browse into their target on a click
 * ANYWHERE in the row (not only on the name link), so a user is not forced to
 * hit the narrow link. Clicks in a folder row's actions cell (the ⋮ button +
 * its menu) are excluded so those controls keep working. File rows do nothing
 * on left-click. The row classes `folder-row` / `parent-row` drive the pointer
 * cursor (see app.css).
 * ========================================================================= */
describe('click-to-browse rows', () => {
  it('folder rows carry `folder-row`, the ".." parent row carries `parent-row`, and file rows carry neither', async () => {
    const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });
    const file = fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false });
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs/sub', parent: 'docs', entries: [dir, file] }));

    const rows = dataRows(results.querySelector('table')!);
    expect(rows).toHaveLength(3); // parent + folder + file
    const [parentRow, folderRow, fileRow] = rows;
    expect(parentRow.classList.contains('parent-row')).toBe(true);
    expect(folderRow.classList.contains('folder-row')).toBe(true);
    expect(fileRow.classList.contains('folder-row')).toBe(false);
    expect(fileRow.classList.contains('parent-row')).toBe(false);
    // Exactly the two navigable rows carry a click-to-browse class.
    expect(document.querySelectorAll('.folder-row, .parent-row')).toHaveLength(2);
  });

  it('clicking the Size cell of a folder row navigates into the folder', async () => {
    const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [dir] }));

    const folderRow = rowByName(results.querySelector('table')!, 'sub')!;
    cellsOf(folderRow)[1].click(); // Size cell (em-dash) — not the name link

    expect(window.location.hash).toBe(toBrowseHash('docs/sub'));
  });

  it('clicking the Modified cell of a folder row navigates into the folder', async () => {
    const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [dir] }));

    const folderRow = rowByName(results.querySelector('table')!, 'sub')!;
    cellsOf(folderRow)[2].click(); // Modified cell

    expect(window.location.hash).toBe(toBrowseHash('docs/sub'));
  });

  it('clicking the ".." parent row (not its link) navigates to the parent path', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs/sub', parent: 'docs', entries: [] }));

    const parentRow = rowByName(results.querySelector('table')!, '..')!;
    cellsOf(parentRow)[2].click(); // Modified cell — not the ".." link

    expect(window.location.hash).toBe(toBrowseHash('docs'));
  });

  it('clicking a file row does NOT navigate', async () => {
    const file = fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false });
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [file] }));
    window.location.hash = '';

    rowByName(results.querySelector('table')!, 'a.txt')!.click();

    expect(window.location.hash).toBe('');
  });

  it('clicking the ⋮ button (in the actions cell) opens the menu and does NOT navigate', async () => {
    const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [dir] }));
    window.location.hash = '';

    const folderRow = rowByName(results.querySelector('table')!, 'sub')!;
    const btn = cellsOf(folderRow)[3].querySelector('.row-menu-btn') as HTMLButtonElement;
    const menu = cellsOf(folderRow)[3].querySelector('.row-menu') as HTMLElement;
    btn.click();

    expect(menu.hidden).toBe(false); // menu opened
    expect(window.location.hash).toBe(''); // no navigation from the actions cell
  });
});

/**
 * Tests for the toolbar handlers — the search button / Enter-key handler and
 * the upload (change) handler, including the per-file upload error-handling
 * contract.
 *
 * Split out of the former `src/app.test.ts` monolith (task-29). Shared
 * fixtures, DOM scaffolding, and the per-test fetch stub come from
 * `./test-helpers`.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 */
import { describe, it, expect } from 'vitest';
import { toBrowseHash, toSearchHash } from '../router';
import { normalizeRelativePath } from '../format';
import { mockResponse } from '../test-utils/mock-response';
import {
  setup,
  flush,
  browseResult,
  fileEntry,
  joinPathHelper,
  fetchMock,
  installAppTestLifecycle,
} from './test-helpers';
import { pickAndUploadInto } from './toolbar-handlers';

installAppTestLifecycle();

/* ===========================================================================
 * Toolbar handlers
 * ========================================================================= */
describe('toolbar handlers', () => {
  describe('search', () => {
    it('navigates to a search hash for the input value and current path when the Search button is clicked', async () => {
      const { searchInput, searchBtn } = setup({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = 'hello world';
      searchBtn.click();

      expect(window.location.hash).toBe(toSearchHash('hello world', normalizeRelativePath('docs')));
    });

    it('trims the query before navigating', async () => {
      const { searchInput, searchBtn } = setup({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = '   spaced   ';
      searchBtn.click();

      expect(window.location.hash).toBe(toSearchHash('spaced', 'docs'));
    });

    it('clears the search (returns to browse) when the query is empty', async () => {
      const { searchInput, searchBtn } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = '';
      searchBtn.click();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('clears the search when the query is only whitespace', async () => {
      const { searchInput, searchBtn } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = '   \t  ';
      searchBtn.click();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('navigates when Enter is pressed inside the search input', async () => {
      const { searchInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = 'foo';
      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter' }));

      expect(window.location.hash).toBe(toSearchHash('foo', 'docs'));
    });
  });

  describe('upload', () => {
    function setFiles(input: HTMLInputElement, names: string[]): void {
      const dt = new DataTransfer();
      for (const n of names) dt.items.add(new File(['data-' + n], n));
      input.files = dt.files as unknown as FileList;
    }

    /** Drain queued microtasks enough times for the upload loop + re-render. */
    const settle = async (n = 10): Promise<void> => {
      for (let i = 0; i < n; i++) await flush();
    };

    /**
     * Build a fetch impl that rejects POST /upload for the named files (via a
     * non-ok Response, exactly how `ApiClient.request` surfaces failures) while
     * still serving normal browse/upload responses for everything else.
     */
    function failingUploadImpl(failingNames: string[]) {
      const failing = new Set(failingNames);
      return async (url: string, init?: RequestInit): Promise<Response> => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'POST' && u.includes('/upload')) {
          const file = (init?.body as FormData | undefined)?.get('file') as File | null;
          if (file && failing.has(file.name)) {
            return mockResponse({ ok: false, status: 413, text: 'too large' });
          }
          return mockResponse({ status: 200, body: { path: file?.name ?? '' } });
        }
        if (method === 'GET' && u.includes('/browse')) {
          const raw = u.split('path=')[1] ?? '';
          const path = decodeURIComponent(raw);
          const child = 'child-of-' + (path || 'root');
          return mockResponse({
            body: browseResult({
              path,
              entries: [fileEntry({ name: child, path: joinPathHelper(path, child) })],
              fileCount: 1,
              totalSize: 10,
            }),
          });
        }
        return mockResponse({ status: 200, body: {} });
      };
    }

    /** Ordered names of files POSTed to /upload so far. */
    function uploadedFileNames(): string[] {
      return fetchMock.mock.calls
        .filter(([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST')
        .map(
          ([, init]) =>
            ((init?.body as FormData | undefined)?.get('file') as File | null)?.name ?? '',
        );
    }

    /** Count of GET /browse calls observed so far. */
    function browseCount(): number {
      return fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/browse') && (init?.method ?? 'GET') === 'GET',
      ).length;
    }

    it('uploads each selected file to the current browse path, then clears the input and re-renders', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await flush();
      await flush();

      const uploadCalls = fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST',
      );
      expect(uploadCalls).toHaveLength(2);
      for (const [, init] of uploadCalls) {
        expect(init?.body).toBeInstanceOf(FormData);
        expect((init!.body as FormData).get('file')).toBeInstanceOf(File);
      }
      // All uploads target the current browse path.
      expect(
        uploadCalls.every(([u]) => String(u).includes('path=' + encodeURIComponent('docs'))),
      ).toBe(true);
      // The input is cleared afterwards.
      expect(uploadInput.value).toBe('');
      // And a re-render occurred (browse fetched again after upload).
      const browseCalls = fetchMock.mock.calls.filter(([u]) => String(u).includes('/browse'));
      expect(browseCalls.length).toBeGreaterThan(0);
    });

    it('uploads nothing when no files are selected', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      uploadInput.dispatchEvent(new Event('change'));
      await flush();

      expect(fetchMock.mock.calls.some(([u]) => String(u).includes('/upload'))).toBe(false);
    });

    // ---- per-file error handling -------------------------------------------
    // A single failing upload must NOT abort the remaining uploads, swallow the
    // re-render, or leave the input uncleared. Each failure is surfaced in the
    // status footer (see task spec: "Uploaded N file(s); failed: a.txt, b.txt").

    it('continues uploading the remaining files when a middle upload fails, then clears the input, re-renders, and surfaces the failure', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['b.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['a.txt', 'b.txt', 'c.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      // All three uploads were attempted — including the failing one — in order.
      expect(uploadedFileNames()).toEqual(['a.txt', 'b.txt', 'c.txt']);
      // The input is cleared even though one upload failed.
      expect(uploadInput.value).toBe('');
      // A re-render still happened after the upload loop.
      expect(browseCount()).toBeGreaterThan(browseBefore);
      // The failure is surfaced in the status footer: it names the failing
      // file and acknowledges the two files that did upload.
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('b.txt');
      expect(status.textContent).toMatch(/Uploaded\s+2/i);
      // Successful files are not flagged as failed.
      expect(status.textContent).not.toContain('c.txt');
      expect(status.textContent).not.toContain('a.txt');
    });

    it('continues uploading subsequent files when the first upload fails', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['bad.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['bad.txt', 'good.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['bad.txt', 'good.txt']);
      expect(uploadInput.value).toBe('');
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('bad.txt');
      expect(status.textContent).not.toContain('good.txt');
    });

    it('clears the input, re-renders, and lists every failure when all uploads fail', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['x.txt', 'y.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['x.txt', 'y.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['x.txt', 'y.txt']);
      expect(uploadInput.value).toBe('');
      expect(browseCount()).toBeGreaterThan(browseBefore);
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('x.txt');
      expect(status.textContent).toContain('y.txt');
    });

    it('does not surface a failure message when every upload succeeds (status stays the normal browse summary)', async () => {
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadInput.value).toBe('');
      // No failure report; renderBrowse's normal "N folders, M files, total S"
      // summary is what the re-render leaves behind.
      expect(status.textContent).not.toMatch(/failed/i);
      expect(status.textContent).toMatch(/folders.*files.*total/);
    });
  });

  describe('pickAndUploadInto (upload into an arbitrary folder)', () => {
    // Exercises pickAndUploadInto directly: it builds a transient
    // <input type=file multiple>, awaits its change/cancel, uploads every
    // chosen file into the GIVEN path (not the current route), then removes
    // the input and re-renders — mirroring handleUpload's contract but with a
    // caller-chosen destination.

    /** Grab the transient picker input that pickAndUploadInto appended to body. */
    function findPickerInput(): HTMLInputElement | undefined {
      // The transient input is a DIRECT child of <body>; the toolbar upload
      // input lives inside <label class="btn">, so its parent is not body.
      return Array.from(document.querySelectorAll('input[type=file]')).find(
        (i) => i.parentElement === document.body,
      ) as HTMLInputElement | undefined;
    }

    function setFiles(input: HTMLInputElement, names: string[]): void {
      const dt = new DataTransfer();
      for (const n of names) dt.items.add(new File(['data-' + n], n));
      input.files = dt.files as unknown as FileList;
    }

    const settle = async (n = 10): Promise<void> => {
      for (let i = 0; i < n; i++) await flush();
    };

    function uploadCalls(): [string, RequestInit | undefined][] {
      return fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST',
      );
    }

    it('creates a hidden <input type=file multiple> appended to body, then uploads each file into the given path', async () => {
      setup({ hash: toBrowseHash('current/dir') });
      await flush();

      // Suspend on the awaited picker: do NOT await yet.
      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      expect(pickInput, 'a transient picker input must be appended to body').toBeTruthy();
      expect(pickInput!.type).toBe('file');
      expect(pickInput!.multiple).toBe(true);

      setFiles(pickInput!, ['a.txt', 'b.txt']);
      pickInput!.dispatchEvent(new Event('change'));
      await p;
      await settle();

      // Uploads target the GIVEN path, NOT the current route.
      expect(uploadCalls()).toHaveLength(2);
      expect(
        uploadCalls().every(([u]) =>
          String(u).includes('path=' + encodeURIComponent('target/folder')),
        ),
      ).toBe(true);
      // The transient input was removed after the upload loop.
      expect(findPickerInput()).toBeUndefined();
    });

    it('uploads nothing and removes the input when the picker is cancelled (no files)', async () => {
      setup({ hash: toBrowseHash('docs') });
      await flush();

      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      expect(pickInput).toBeTruthy();

      // Dismiss the picker without choosing — the `cancel` event resolves
      // the awaited promise with an empty list.
      pickInput!.dispatchEvent(new Event('cancel'));
      await p;
      await settle();

      expect(uploadCalls()).toHaveLength(0);
      expect(findPickerInput()).toBeUndefined();
    });

    it('surfaces per-file failures in the status footer while still uploading the rest', async () => {
      fetchMock.mockImplementation(async (url: string, init?: RequestInit) => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'POST' && u.includes('/upload')) {
          const file = (init?.body as FormData | undefined)?.get('file') as File | null;
          if (file && file.name === 'bad.txt') {
            return mockResponse({ ok: false, status: 413, text: 'too large' });
          }
          return mockResponse({ status: 200, body: { path: file?.name ?? '' } });
        }
        if (method === 'GET' && u.includes('/browse')) {
          return mockResponse({ body: browseResult({ path: 'target/folder', entries: [] }) });
        }
        return mockResponse({ status: 200, body: {} });
      });
      const { status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      setFiles(pickInput!, ['good.txt', 'bad.txt']);
      pickInput!.dispatchEvent(new Event('change'));
      await p;
      await settle();

      // Both were attempted; only bad.txt is flagged.
      expect(
        uploadCalls().map(([, init]) => ((init!.body as FormData).get('file') as File).name),
      ).toEqual(['good.txt', 'bad.txt']);
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('bad.txt');
      expect(status.textContent).not.toContain('good.txt');
    });
  });
});

